      assert String.contains?(to_string(result.content), "Normal")
    end
  end

  describe "visitor_subscript_custom" do
    test "visitor_subscript_custom" do
      visitor = %{
      :handle_subscript => fn(args) ->
        {:custom, "~" <> Map.get(args, "text", "") <> "~"}
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<p>H<sub>2</sub>O is water.</p>", %{visitor: visitor})
      assert String.contains?(to_string(result.content), "H~2~O")
      assert String.contains?(to_string(result.content), "is water")
    end
  end

  describe "visitor_subscript_skip" do
    test "visitor_subscript_skip" do
      visitor = %{
      :handle_subscript => fn(_args) ->
        :skip
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<p>The formula C<sub>12</sub>H<sub>22</sub>O<sub>11</sub> is sugar.</p>", %{visitor: visitor})
      assert String.contains?(to_string(result.content), "The formula CHO is sugar.")
    end
  end

  describe "visitor_superscript_custom" do
    test "visitor_superscript_custom" do
      visitor = %{
      :handle_superscript => fn(args) ->
        {:custom, "^" <> Map.get(args, "text", "") <> "^"}
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<p>Einstein's E=mc<sup>2</sup> revolutionized physics.</p>", %{visitor: visitor})
      assert String.contains?(to_string(result.content), "E=mc^2^")
      assert String.contains?(to_string(result.content), "revolutionized physics")
    end
  end

  describe "visitor_superscript_skip" do
    test "visitor_superscript_skip" do
      visitor = %{
      :handle_superscript => fn(_args) ->
        :skip
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<p>The equation x<sup>3</sup> + y<sup>3</sup> = z<sup>3</sup> has no solutions.</p>", %{visitor: visitor})
      assert String.contains?(to_string(result.content), "The equation x + y = z has no solutions.")
    end
  end

  describe "visitor_underline_custom" do
    test "visitor_underline_custom" do
      visitor = %{
      :handle_underline => fn(args) ->
        {:custom, "_" <> Map.get(args, "text", "") <> "_"}
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<p>This is <u>very important</u> text.</p>", %{visitor: visitor})
      assert String.contains?(to_string(result.content), "_very important_")
      refute String.contains?(to_string(result.content), "**")
    end
  end

  describe "visitor_underline_skip" do
    test "visitor_underline_skip" do
      visitor = %{
      :handle_underline => fn(_args) ->
        :skip
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<p>Normal text with <u>underlined part</u> and more text.</p>", %{visitor: visitor})
      assert String.contains?(to_string(result.content), "Normal text with")
      assert String.contains?(to_string(result.content), "and more text.")
      refute String.contains?(to_string(result.content), "underlined part")
    end
  end

  describe "visitor_video_custom" do
    test "visitor_video_custom" do
      visitor = %{
      :handle_video => fn(args) ->
        {:custom, "[VIDEO: " <> Map.get(args, "src", "") <> "]"}
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<p>Watch our tutorial:</p><video src=\"tutorial.mp4\" width=\"320\" height=\"240\" controls></video><p>Great content!</p>", %{visitor: visitor})
      assert String.contains?(to_string(result.content), "[VIDEO: tutorial.mp4]")
      assert String.contains?(to_string(result.content), "Watch our tutorial:")
      assert String.contains?(to_string(result.content), "Great content!")
    end
  end

  describe "visitor_video_skip" do
    test "visitor_video_skip" do
      visitor = %{
      :handle_video => fn(_args) ->
        :skip
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<h2>Demo</h2><video src=\"demo.webm\"></video><p>See the demo above.</p>", %{visitor: visitor})
      assert String.contains?(to_string(result.content), "Demo")
      assert String.contains?(to_string(result.content), "See the demo above.")
      refute String.contains?(to_string(result.content), "demo.webm")
    end
  end
end
